import heapq

def trap_rain_water(height_map):
    if not height_map or not height_map[0]:
        return 0
    m, n = len(height_map), len(height_map[0])
    visited = [[False] * n for _ in range(m)]
    heap = []

    for i in range(m):
        for j in range(n):
            if i == 0 or i == m - 1 or j == 0 or j == n - 1:
                heapq.heappush(heap, (height_map[i][j], i, j))
                visited[i][j] = True

    dirs = [(0, 1), (0, -1), (1, 0), (-1, 0)]
    water = 0

    while heap:
        height, r, c = heapq.heappop(heap)
        for dr, dc in dirs:
            nr, nc = r + dr, c + dc
            if 0 <= nr < m and 0 <= nc < n and not visited[nr][nc]:
                visited[nr][nc] = True
                if height_map[nr][nc] < height:
                    water += height - height_map[nr][nc]
                heapq.heappush(heap, (max(height, height_map[nr][nc]), nr, nc))
    return water

def calc_equation(equations, values, queries):
    graph = {}
    for (a, b), val in zip(equations, values):
        if a not in graph:
            graph[a] = {}
        if b not in graph:
            graph[b] = {}
        graph[a][b] = val
        graph[b][a] = 1 / val

    def dfs(a, b, visited):
        if a not in graph or b not in graph:
            return -1.0
        if b in graph[a]:
            return graph[a][b]
        for neighbor in graph[a]:
            if neighbor not in visited:
                visited.add(neighbor)
                result = dfs(neighbor, b, visited)
                if result != -1.0:
                    return result * graph[a][neighbor]
        return -1.0

    return [dfs(a, b, {a}) for a, b in queries]

